+            )
+            .expect("oracle seed insert");
+    }
+    oracle
+        .execute(
+            "CREATE INDEX IF NOT EXISTS idx_schema_mix_category ON schema_mix(category);",
+            [],
+        )
+        .expect("oracle create index");
