+        oracle
+            .execute(
+                "INSERT INTO schema_mix(id, category, payload) VALUES (?1, 'writer', ?2);",
+                rusqlite::params![id, format!("writer-payload-{id:04}")],
+            )
+            .expect("oracle writer insert");
+    }
+
+    {
