+        setup.execute(
+            "CREATE TABLE schema_mix(id INTEGER PRIMARY KEY, category TEXT NOT NULL, payload TEXT NOT NULL);",
+        )
+        .expect("candidate schema");
+        for id in 0_i64..512 {
+            let sql = format!(
+                "INSERT INTO schema_mix(id, category, payload) VALUES ({id}, '{}', '{}');",
